sql:
SELECT games.name
FROM games
WHERE games.is_featured = 1;

SELECT COUNT(*) 
FROM comments 
WHERE user_id IN (SELECT DISTINCT user_id FROM ratings WHERE rating IS NOT NULL);

SELECT games.name, genres.genre_name
FROM games
INNER JOIN genres ON games.genre_id = genres.genre_id;

SELECT games.name
FROM games
WHERE games.is_featured = 1 AND games.rating_avg > 4.5;

SELECT AVG(rating_avg) AS average_rating
FROM games
WHERE num_ratings > 2000;

SELECT AVG(num_comments) AS average_num_comments
FROM games
WHERE rating_avg >= 4;

